questions.solutionCode:
function solve(eventJson) {
  const event = JSON.parse(eventJson);
  const payload = event.payload;
  const operation = payload.op;
  const schema = payload.source.schema;
  const table = payload.source.table;
  let changedFields;
  if (operation === 'u' && payload.before && payload.after) {
    // Для UPDATE -- только поля с отличающимися значениями
    changedFields = Object.keys(payload.after)
      .filter(k => JSON.stringify(payload.before[k]) !== JSON.stringify(payload.after[k]))
      .sort();
  } else if (operation === 'd') {
    changedFields = Object.keys(payload.before).sort();
  } else {
    changedFields = Object.keys(payload.after).sort();
  }
  return { operation, schema, table, changedFields };
}
